angular.module('changeBaseLayerPanel', []);
angular.module('changeBaseLayerPanel').directive('changeBaseLayerPanel', [
  'changeBaseLayerPanelFactory',
  'ISY.MapAPI.Map',
  function (changeBaseLayerPanelFactory, map) {
    return {
      templateUrl: 'components/transclusions/changeBaseLayerPanel/changeBaseLayerPanel.html',
      restrict: 'A',
      link: function (scope) {
        scope.allBaseLayers = function () {
          return changeBaseLayerPanelFactory.getAllBaseLayers();
        };
        scope.toggleBaseLayer = function (id) {
          var baseMapLayers = map.GetBaseLayers();
          for (var i = 0; i < baseMapLayers.length; i++) {
            if (baseMapLayers[i].thumbnail === id) {
              map.SetBaseLayer(baseMapLayers[i]);
              changeBaseLayerPanelFactory.setBaseLayerById(id);
            }
          }
        };
        scope.activeBaseLayer = function () {
          return changeBaseLayerPanelFactory.getSelectedBaseLayer();
        };
        _initBaseLayers = function () {
          var baseMapLayers = map.GetBaseLayers();
          for (var i = 0; i < baseMapLayers.length; i++) {
            if (baseMapLayers[i].thumbnail !== '' && baseMapLayers[i].isVisible) {
              changeBaseLayerPanelFactory.setBaseLayerById(baseMapLayers[i].thumbnail);
            }
          }
        };
        $(document).ready(function () {
          _initBaseLayers();
        });
        scope.$on('initBaseLayers', function () {
          _initBaseLayers();
        });
      }
    };
  }
]);
angular.module('changeBaseLayerPanel').factory('changeBaseLayerPanelFactory', [function () {
    var baseLayers = [
        {
          id: 'land',
          title: 'Land',
          symbol: 'baseMap-land',
          isSelected: false
        },
        {
          id: 'raster',
          title: 'Raster',
          symbol: 'baseMap-raster',
          isSelected: false
        },
        {
          id: 'aerial',
          title: 'Flybilder',
          symbol: 'baseMap-aerial',
          isSelected: false
        },
        {
          id: 'grey',
          title: 'Graatone',
          symbol: 'baseMap-grey',
          isSelected: false
        }
      ];
    return {
      getAllBaseLayers: function () {
        return baseLayers;
      },
      getSelectedBaseLayer: function () {
        for (var i = 0; i < baseLayers.length; i++) {
          if (baseLayers[i].isSelected) {
            return baseLayers[i];
          }
        }
        return undefined;
      },
      setBaseLayerById: function (id) {
        if (id !== undefined) {
          for (var i = 0; i < baseLayers.length; i++) {
            baseLayers[i].isSelected = baseLayers[i].id.toLowerCase() === id.toLowerCase();
          }
        } else {
          this.deactivateAllBaseLayers();
        }
      },
      deactivateAllBaseLayers: function () {
        for (var i = 0; i < baseLayers.length; i++) {
          baseLayers[i].isSelected = false;
        }
      }
    };
  }]);
angular.module('mainMenuBaseLayers', []);
angular.module('mainMenuBaseLayers').directive('mainMenuBaseLayers', [
  'ISY.MapAPI.Map',
  'changeBaseLayerPanelFactory',
  'mapOverlaysLayoutFactory',
  function (map, changeBaseLayerPanelFactory, mapOverlaysLayoutFactory) {
    return {
      templateUrl: 'components/transclusions/mainMenuPanel/mainMenuBaseLayers/mainMenuBaseLayers.html',
      restrict: 'A',
      link: function (scope) {
        scope.baseLayers = map.GetBaseLayers();
        scope.baseLayers.sort(function (a, b) {
          if (a.guid && b.guid) {
            return a.guid - b.guid;
          } else {
            return 0;
          }
        });
        scope.getBaseLayerStyle = function (baseLayer) {
          if (baseLayer.isVisible) {
            return 'icon-radio-checked pointer-cursor';
          } else {
            return 'icon-radio-unchecked pointer-cursor';
          }
        };
        scope.setAsBaseLayer = function (baseLayer) {
          map.SetBaseLayer(baseLayer);
          map.ZoomToLayer(baseLayer);
          scope.baseLayers = map.GetBaseLayers();
          scope.baseLayers.sort(function (a, b) {
            if (a.guid && b.guid) {
              return a.guid - b.guid;
            } else {
              return 0;
            }
          });
          mapOverlaysLayoutFactory.setBaseLayerByName(baseLayer.name);
          if (baseLayer.thumbnail !== '') {
            changeBaseLayerPanelFactory.setBaseLayerById(baseLayer.thumbnail);
          } else {
            changeBaseLayerPanelFactory.deactivateAllBaseLayers();
          }
        };
      }
    };
  }
]);
